-- =====================================================
-- Percheros Decorativos — Migración de catálogo a Supabase
-- Ejecutar en: Supabase Dashboard → SQL Editor (una sola vez)
--
-- Antes de correr esto, crea el bucket de Storage para fotos nuevas:
--   Storage → New bucket → nombre "product-images" → Public bucket: ON
-- No hace falta política adicional: las escrituras solo las hace el
-- servidor con la service_role key (supabaseAdmin), igual que "orders".
-- =====================================================

create table if not exists products (
  id             bigint generated always as identity primary key,
  slug           text unique not null,
  name           text not null,
  category_slug  text not null,
  reference      text,
  short_desc     text,
  description    text,
  materials      text,
  dimensions     text,
  hardware       text,
  warranty       text default '6 meses',
  price_cop      numeric(12,2) not null,
  compare_at_cop numeric(12,2),
  stock          integer not null default 0,
  featured       boolean default false,
  is_new         boolean default false,
  images         jsonb not null default '[]',
  created_at     timestamptz default now(),
  updated_at     timestamptz default now()
);

create index if not exists idx_products_category on products(category_slug);
create index if not exists idx_products_slug on products(slug);

create or replace trigger products_updated_at
  before update on products
  for each row execute function set_updated_at();

