-- Deja la secuencia lista para que el próximo producto creado desde el
-- panel siga en 40 en vez de chocar con estos ids explícitos.
select setval(
  pg_get_serial_sequence('products', 'id'),
  (select coalesce(max(id), 1) from products)
);
